def getOrderData(user_id, order_id):
    db = open("orders.db") # Create a connection to SQLite database file orders.db
    cursor = db.cursor()

    sql = '''select * from orders where user_id=%d and id=%d''' % (user_id,order_id)
    result = executeSQL(db,sql)

    cursor.close()
    return result